282	/**
283	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
284	 *
285	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
286	 * - `system`: render the cell as a solid panel using a registered
287	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
288	 * - `family_instance`: instantiate a custom family at this cell. Until
289	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
290	 */
291	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
