332	/**
333	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
334	 *
335	 * `linkId` (when set) names a `link_model` element in the host whose source
336	 * model contains the monitored element; intra-host monitors omit it.
337	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
338	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
339	 * counter at the moment of the copy; the BumpMonitoredRevisions command
340	 * compares it against the latest revision and flags drift.
341	 *
342	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
343	 * persist on the host element so the constraint evaluator can emit a
344	 * `monitored_source_drift` advisory without needing live source access.
345	 */
346	export type MonitorSource = {
347	  linkId?: string | null;
348	  elementId: string;
349	  sourceRevisionAtCopy: number;
350	  drifted?: boolean;
351	  driftedFields?: string[];
352	};
