          border: '1px solid var(--border-subtle)',
          borderRadius: 3,
          color: 'var(--text-primary)',
          fontSize: 'var(--text-xs)',
          padding: '2px 6px',
          width: '100%',
        }}
      />
    </label>
  );
}

export function AssetPreviewPane({ entry, onPlace }: AssetPreviewPaneProps): ReactElement {
